import React from 'react';
import {
    RadarChart, Radar, PolarGrid, PolarAngleAxis, ResponsiveContainer,
} from 'recharts';

/* ── Mini circular gauge ────────────────────────────────────── */
function CircleGauge({ value, max = 100, color = '#4f8cff', size = 72 }) {
    const r = (size - 8) / 2;
    const circumference = 2 * Math.PI * r;
    const pct = Math.min(Math.max(value / max, 0), 1);
    const dashOffset = circumference * (1 - pct);
    return (
        <svg width={size} height={size}>
            <circle cx={size / 2} cy={size / 2} r={r} fill="none" stroke="rgba(255,255,255,0.06)" strokeWidth={6} />
            <circle
                cx={size / 2} cy={size / 2} r={r}
                fill="none" stroke={color} strokeWidth={6} strokeLinecap="round"
                strokeDasharray={circumference} strokeDashoffset={dashOffset}
                transform={`rotate(-90 ${size / 2} ${size / 2})`}
                style={{ transition: 'stroke-dashoffset 0.8s ease' }}
            />
            <text x={size / 2} y={size / 2 + 1} textAnchor="middle" dominantBaseline="middle"
                fill="white" fontSize="14" fontWeight="700" fontFamily="Inter, sans-serif">
                {Math.round(value)}
            </text>
        </svg>
    );
}

/* ── Score row ──────────────────────────────────────────────── */
function ScoreRow({ label, value, max = 100, color }) {
    const pct = Math.min((value / max) * 100, 100);
    return (
        <div>
            <div className="flex items-center justify-between mb-1">
                <span className="text-white/60 text-xs">{label}</span>
                <span className="text-white text-xs font-semibold">{value}/{max}</span>
            </div>
            <div className="progress-bar">
                <div className="progress-fill" style={{ width: `${pct}%`, background: color }} />
            </div>
        </div>
    );
}

const dimensionColors = [
    'linear-gradient(90deg,#4f8cff,#a259ff)',
    'linear-gradient(90deg,#00e5a0,#4f8cff)',
    'linear-gradient(90deg,#ffe600,#ff5caa)',
    'linear-gradient(90deg,#a259ff,#ff5caa)',
    'linear-gradient(90deg,#ff5caa,#ffe600)',
];

/**
 * ScoreCard
 * Props:
 *   scores: { overall, fluency, grammar, vocabulary, pronunciation, confidence }
 *   feedback: string
 *   improvementTips: string[]
 *   loading: boolean
 */
export default function ScoreCard({ scores = null, feedback = '', improvementTips = [], loading = false }) {
    if (loading) {
        return (
            <div className="glass-card p-6 flex flex-col items-center gap-4 animate-pulse">
                <div className="w-[72px] h-[72px] rounded-full bg-white/5" />
                <div className="space-y-2 w-full">
                    {[1, 2, 3, 4].map(i => <div key={i} className="h-5 rounded bg-white/5" />)}
                </div>
                <p className="text-white/30 text-sm">Analysing your speech…</p>
            </div>
        );
    }

    if (!scores) {
        return (
            <div className="glass-card p-6 flex flex-col items-center gap-3 text-center">
                <div className="w-14 h-14 rounded-2xl bg-white/5 flex items-center justify-center text-3xl">📊</div>
                <p className="text-white/60 text-sm">Record your speech and submit to see your scores here.</p>
            </div>
        );
    }

    const dimensions = [
        { label: 'Fluency', value: scores.fluency ?? scores.fluencyScore ?? 0 },
        { label: 'Grammar', value: scores.grammar ?? scores.grammarScore ?? 0 },
        { label: 'Vocabulary', value: scores.vocabulary ?? scores.vocabularyScore ?? 0 },
        { label: 'Pronunciation', value: scores.pronunciation ?? scores.pronunciationScore ?? 0 },
        { label: 'Confidence', value: scores.confidence ?? scores.confidenceScore ?? 0 },
    ];

    const overall = scores.overall ?? scores.overallScore ?? 0;
    const overallColor =
        overall >= 80 ? '#00e5a0' :
            overall >= 60 ? '#4f8cff' :
                overall >= 40 ? '#ffe600' : '#ff5caa';

    const badge =
        overall >= 85 ? { label: 'Excellent 🏆', cls: 'bg-neon-green/20 text-neon-green border-neon-green/30' } :
            overall >= 70 ? { label: 'Good 👍', cls: 'bg-primary-500/20 text-primary-400 border-primary-500/30' } :
                overall >= 50 ? { label: 'Fair ⚡', cls: 'bg-neon-yellow/20 text-neon-yellow border-neon-yellow/30' } :
                    { label: 'Needs Work 💪', cls: 'bg-neon-pink/20 text-neon-pink border-neon-pink/30' };

    // Radar chart data — normalise to 0-100
    const radarData = dimensions.map(d => ({
        subject: d.label,
        score: Math.min(Math.round(d.value), 100),
        fullMark: 100,
    }));

    return (
        <div className="glass-card p-6 space-y-5 animate-fadeInUp">
            {/* Header */}
            <div className="flex items-center gap-4">
                <CircleGauge value={overall} color={overallColor} />
                <div>
                    <p className="text-white/50 text-xs mb-1">Overall Score</p>
                    <span className={`badge border ${badge.cls}`}>{badge.label}</span>
                    <p className="text-white/40 text-xs mt-1">out of 100</p>
                </div>
            </div>

            {/* ── Radar Chart ─────────────────────────────────── */}
            <div className="h-52">
                <ResponsiveContainer width="100%" height="100%">
                    <RadarChart data={radarData} margin={{ top: 5, right: 15, bottom: 5, left: 15 }}>
                        <PolarGrid stroke="rgba(255,255,255,0.08)" />
                        <PolarAngleAxis
                            dataKey="subject"
                            tick={{ fill: 'rgba(255,255,255,0.5)', fontSize: 10 }}
                        />
                        <Radar
                            name="Score"
                            dataKey="score"
                            stroke="#4f8cff"
                            fill="#4f8cff"
                            fillOpacity={0.25}
                            strokeWidth={2}
                        />
                    </RadarChart>
                </ResponsiveContainer>
            </div>

            {/* Dimension bars */}
            <div className="space-y-3">
                {dimensions.map((d, i) => (
                    <ScoreRow key={d.label} label={d.label} value={d.value}
                        color={dimensionColors[i]} />
                ))}
            </div>

            {/* AI Feedback */}
            {feedback && (
                <div className="p-3 rounded-xl bg-white/5 border border-white/10">
                    <p className="text-white/40 text-[10px] uppercase tracking-wider mb-1">AI Feedback</p>
                    <p className="text-white/80 text-sm leading-relaxed">{feedback}</p>
                </div>
            )}

            {/* ── Improvement Tips ─────────────────────────────── */}
            {improvementTips && improvementTips.length > 0 && (
                <div className="space-y-2">
                    <p className="text-white/40 text-[10px] uppercase tracking-wider">💡 Improvement Tips</p>
                    {improvementTips.map((tip, i) => (
                        <div key={i} className="flex gap-2 p-2.5 rounded-xl bg-primary-600/10 border border-primary-500/20">
                            <span className="text-primary-400 text-xs font-bold flex-shrink-0">{i + 1}.</span>
                            <p className="text-white/70 text-xs leading-relaxed">{tip}</p>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
}
